sp_widget.client_script:
function tpbwfCtrl($scope,spModal, $location, spUtil, amb, $http, spAriaUtil, $timeout, spNavStateManager) {

	// 2.6.0 | 2021-04-06 | mmcc | STRY0097980 - Hover Over Task Name HTML
	// 2.6.0 | 2021-04-26 | mmcc | STRY0100152 - Tasker Modern Portal - Task Name Hover needs a short delay before showing the popup
    //------------------------------------------------------------------------------------------------------------------------

	var c = this;
	/*
 	* options:
 	* hide_footer (bool) = true to remove the data table footer contents
 	* hide_header (bool) = true to remove the data table header contents
 	* show_new (bool) = true to show the "New" record button
 	* show_keywords (bool) = true to show the keyword search field
 	* table (string) = the table name to query
 	* filter (string) = the encoded query
 	* o (string) = the order by column
 	* d (string) = The order by direction: asc or desc
 	* p (int) = the page to jump to
 	* fields (string) = comma seperated list of fields that become the list columns
 	* view (string) = the default view to load for columns, overrides fields
 	*/
	$scope.exportTypes = [{label:'PDF', value: 'PDF'}, {label:'Excel', value:'EXCEL'}, {label:'CSV', value:'CSV'}];
		var keys = ['table', 'filter', 'p', 'o', 'd'];

		var eventNames = {
			click: 'data_table.click',
			setFilter: 'data_table.setFilter',
			setKeywords: 'data_table.setKeywords'
		};
		// AAlzyoud Custom Starts here
		//-----------------------------------------------------------------------------
		c.getData = function(data){
			$scope.setPageNum(1);
			$rootScope.$broadcast("dropdownMenuClicked",data);
			initRecordWatcher(data.table, data.filter);
		};

		$scope.$on("countPanelClicked",function(evt,data){
			c.data.table = data.table;
			c.data.filter = data.filter;
			c.data.sp_page_dv = data.sp_page_dv;
			c.data.title = data.title;
			c.data.d = data.d;
			c.data.o = data.o;
			$scope.server.update().then(function() {
				// DFCT0010566
				loadFilterWidget();
			});
		});

		$scope.$on("dropdownMenuClicked", function(evt,data){
			c.data.table = data.table;
			c.data.filter = data.filter;
			c.data.sp_page_dv = data.view_all_page;
			c.data.title = data.filter_label;
			c.data.d = data.d;
			c.data.o = data.o;
			c.data.modal_title_field_separator = data.modal_title_field_separator;
			c.data.modal_title_fields = data.modal_title_fields;
			// STRY0108629
			c.data.DiscoverControllerURL = data.DiscoverControllerURL;
			c.data.include_comments = data.include_comments;
			if(data.field_list != undefined && data.field_list != ''){
				c.data.field_list = data.field_list;
			} else {
				c.data.field_list = undefined;
			}
			// STRY0101803 added this call so the data table is reset on the filter every time
			$scope.server.update().then(function() {
				loadFilterWidget();
			});
		});

	// STRY0101803 added this call so the data table is reset on the filter every time
	function loadFilterWidget() {	
		c.data.filterBreadcrumbs = null;
		spUtil.get('widget-filter-breadcrumbs', {
			table: c.data.table,
			query: c.data.filter,
			enable_filter: c.data.enable_filter
		}).then(function(response) {
			c.data.filterBreadcrumbs = response;
		});
	}

	// 2.6.0 | 2021-04-26 | mmcc | STRY0100152 - Make sure all other tooltips are closed except for the 1 passed in, no stuck open tooltips
	c.closeOtherTooltips = function(tooltipItem) {
		c.data.list.forEach(function(rowItem) {
			if (tooltipItem.sys_id !== rowItem.sys_id) {
				rowItem.isTooltipOpened = false;
			}
		});
	};

// 2.6.0 | 2021-04-26 | mmcc | STRY0100152 - Comment out unused c.openPopover = function() and c.closePopover = function()
// 		// open popover
// 		c.openPopover = function(e,sys_id){
// 			// show tooltip
// 			// 2.6.0 | 2021-04-06 | mmcc | STRY0097980 - Hover Over Task Name HTML; unused var's
// 			// var offset = $("#short").offset();
// 			// var topOffset = $("#short").offset().top - $(window).scrollTop();

// 			$("#floaty").css('display','block');
// 			$("#floaty").css({
// 				position: "fixed",
// 				// 2.6.0 | 2021-04-06 | mmcc | STRY0097980 - Hover Over Task Name HTML; use new top and left values
// 				// top: (e.pageY + 5 )+ "px",
// 				// left: (e.pageX + 5) + "px",
// 				top: (e.pageY - 100)+ "px", // move it up
// 				left: (e.pageX + 15) + "px", // move it right
// 				zIndex: 10000
// 			});

// 			// populate tool tip info
// 			c.title = c.data.popOverRecord[sys_id].title;
// 			c.objective =  c.data.popOverRecord[sys_id].objective;
// 			c.state = c.data.popOverRecord[sys_id].state;
// 			c.classification = c.data.popOverRecord[sys_id].classification;
// 			c.status= c.data.popOverRecord[sys_id].status;
// 			c.taskType = c.data.popOverRecord[sys_id].taskType;

// 		};
// 		c.closePopover = function(){
// 			// 2.6.0 | 2021-04-06 | mmcc | STRY0097980 - Hover Over Task Name HTML; no id="instructions", objective empty gives bad results
// 			// $("#instructions").empty();
// 			$("#floaty").css("display", "none");

// 		};

		c.openNewPage = function(table, sys_id, item){
			// TODO, LOOK UP PAGE AND VIEWS SOMEHOW MAYBE A CLIENT SCRIPT CALLBACK
			// NOTE: remove item when calling server
			var portal_url_ref = '../discovertaskerportal';
			var pageId; 
			var pageTable;
			var view = 'sp';
			// STRY0108629
			var ref_field_name = item.dcu_ref;
			switch (table) {
				case 'x_153465_discovert_tasker_requests':
					// STRY0108629
					if(item.parentType == 'Organizational Unit'){
						pageId = 'discover_simple_processing_form';
						pageTable = 'x_153465_discovert_tasker_requests';
					} else {
						pageId = 'discovertasker_taskdetails';	
						pageTable = 'x_153465_discovert_route_task_instance';
					}
					break;
				case 'x_153465_discovert_tasker_schedule':
					pageTable = 'x_153465_discovert_tasker_schedule';
					pageId = 'scheduled_task_graphic';
					break;
				case 'x_153465_discovert_route_task_instance':
					pageId = 'discovertasker_taskdetails';
					pageTable = table;

// TODO - QUESTION SHOULD THE BE ON SERVER TO GET FULL TASK RECORD?
					var getFormToLoadOptions = c.data.userPreferences.filter(function (pref){
					var matchFailure = 
							(pref.u_task_user.displayValue != '' && pref.u_task_user.displayValue != null && pref.u_task_user.value != c.data.userID) || 
							(pref.u_task_category.displayValue != '' && pref.u_task_category.displayValue != null  && pref.u_task_category.value != item.category.value) ||
							(pref.u_tasker_sub_category.displayValue != '' && pref.u_tasker_sub_category.displayValue != null  && pref.u_tasker_sub_category.value != item.sub_category.value) || 
							(pref.u_task_state.displayValue != '' && pref.u_task_state.displayValue != null  && pref.u_task_state.value != item.state.value) ||
							(pref.u_task_task_type.displayValue != '' && pref.u_task_task_type.displayValue != null  && pref.u_task_task_type.value != item.tasker_type.value);
						if(!matchFailure){
							return pref;
						}
					});
					// If a match was found for this task, then use first item as 
					// form preferences were loaded in order by the ORDER 
					// to override the default settings
					if(getFormToLoadOptions.length > 0){
						var formToLoad = getFormToLoadOptions[0];
						if(formToLoad.u_servicenow_portal_page.displayValue != '' && formToLoad.u_servicenow_portal_page.displayValue != null){
							pageId = formToLoad.u_servicenow_portal_page.value;	
						}
						if(formToLoad.u_servicenow_form_view.displayValue != '' && formToLoad.u_servicenow_form_view.displayValue != null){
							view = formToLoad.u_servicenow_form_view.value;	
						}
						if(formToLoad.u_service_portal.displayValue != '' && formToLoad.u_service_portal.displayValue != null){
							portal_url_ref = '../' + formToLoad.u_service_portal.value;	
						}

					}
					break;
				default:
					pageId = 'discovertasker_taskdetails';
					pageTable = table;


					break;
			}
			// STRY0108629
			var url;
			if(c.data.DiscoverControllerURL){
				// TODO, LOOK UP TABLE (for request, will look up task, but others might use data table.  So, keep that in mind)
				url = portal_url_ref + '?id=' +  pageId + '&dcu_sys_id=' + sys_id + '&dcu_table=' + pageTable + '&dcu_ref=' + ref_field_name + '&dcu_view=' + view + '&query=' + c.data.filter + '&o=' + c.data.o + '&d=' + c.data.d;
			} else {
				// TODO, LOOK UP TABLE (for request, will look up task, but others might use data table.  So, keep that in mind)
				url = portal_url_ref + '?id=' +  pageId + '&sys_id=' + sys_id + '&table=' + pageTable + '&view=' + view;
			}
			window.open(url, '_blank');
		};


		// open quickview modal
		c.quickView = function(table, sys_id, widgetId, item) {
			var title;
			// STRY0101803 - if user didn't set the title fields, use a default setting
			// account for original hard coded settings on rows that don't get updated
			if (c.data.modal_title_fields_array.length == 0){
				if (table == 'x_153465_discovert_route_task_instance') {
					// this is here to cover the default settings
					if (widgetId == 'discovertasker-formtab') {
						title = item.taskernumber.display_value + ': ' + item.short_description.display_value;
					} else if (widgetId == 'tasker_stream_widget') {
						title = c.data.popOverRecord[item.sys_id].number + ': ' + c.data.popOverRecord[item.sys_id].short_description;
					}
				} else {
					title = c.data.title + c.data.modal_title_fields_not_set;
				}				
			} else {
				title = item[c.data.modal_title_fields_array[0]].display_value;
				for (i = 1; i < c.data.modal_title_fields_array.length; i++) {
					title += c.data.modal_title_field_separator + item[c.data.modal_title_fields_array[i]].display_value;
				}				
			}
			spModal.open({
				title: title,
				backdrop:'static',
				widget: widgetId,
				widgetInput: {table: $scope.data.table , sys_id: sys_id, view: 'sp'},
					size: 'lg',
					buttons: []

				}).then( function(){
					/* update model after return from modal */
				});
			};

			// AAlzyoud custom ends here
			//-----------------------------------------------------------------------------
			$scope.go = function(table, item) {
				spNavStateManager.onRecordChange(table).then(function() {
					var parms = {};
						parms.table = table;
						parms.sys_id = item.sys_id;
						parms.record = item;
						$scope.ignoreLocationChange = true;
						for (var x in c.data.list) {
							c.data.list[x].selected = false;
						}
						item.selected = true;
						$scope.$emit(eventNames.click, parms);
					}, function() {
						// do nothing in case of closing the modal by clicking on x
					});
				};

				$scope.newRecord = function(){
					var parms = {
						id: 'form',
						table: $scope.data.table,
						view: $scope.data.view,
						sys_id: '-1'
					};
					if ($scope.data.filter != '')
						parms.query = $scope.data.filter;

					$location.search(parms);
				};

				function recoverStateFromUrl() {
					$scope.data.fields_array = [];
					var s = $location.search();
					for (var x in keys) {
						if (s[keys[x]]) {
							$scope.data[keys[x]] = s[keys[x]];
						}
					}
					$scope.server.update().then(function(data) {
						if (s.sys_id) {
							for (var x in data.list) {
								if (data.list[x].sys_id == s.sys_id) {
									$scope.go(s.table, data.list[x]);
								}
							}
							// DFCT0010566
							loadFilterWidget();
						}
					});
				}

				if ($scope.options.fromUrl) {
					var origSearch = $location.search();
					$scope.$on('$locationChangeSuccess', function(e) {
						var s = $location.search();
						if (origSearch.id !== s.id)
							return;

						if ($scope.ignoreLocationChange){
							$scope.ignoreLocationChange = false;
							return;
						}

						// Helps to recover state when using the browser's back button
						recoverStateFromUrl();
					});
				}

				$scope.getNumber = function(num) {
					return new Array(num);
				};

				$scope.mathMin = function(v1,v2) {
					return Math.min(v1,v2);
				};

				function getData(updateUrl) {
					var f = $scope.data;
					spUtil.update($scope).then(function(data) {
						f.view = data.view;
						if ($scope.options.fromUrl && updateUrl)
							setPermalink(f.table, f.filter, f.o, f.d, f.p);

						initRecordWatcher(f.table, f.filter);
						// DFCT0010547
						loadFilterWidget();
					});
				}

				function setPermalink(table, filter, orderBy, orderDirection, page){
					$scope.ignoreLocationChange = true;
					var search = $location.search();
					angular.extend(search, {
						spa: 1,
						table: table,
						filter: filter,
						p: page,
						o: orderBy,
						d: orderDirection
					});
					$location.search(search);
				}

				var watcher;
				function initRecordWatcher(table, filter){
					if (watcher)
						watcher.unsubscribe();

					if (table && filter) {
						var watcherChannel = amb.getChannelRW(table, filter);
						amb.connect();
						watcher = watcherChannel.subscribe(function(message) {
							if (!message.data)
								return;
							switch(message.data.action) {
								case "change":
								updateRowFromRW(message);
								break;
								case "exit":
								// A record was removed
								case "enter":
								case "entry":
								// A record was added
								default:
								spUtil.update($scope);
								break;
							}
						});
					}
				}

				function updateRowFromRW(message) {
					if (message.data && message.data.sys_id && $scope.data.list) {
						var row, field;
						for(var i=0;i<$scope.data.list.length; i++) {
							row = $scope.data.list[i];
							if (row.sys_id == message.data.sys_id) {
								var fields = Object.getOwnPropertyNames(message.data.record);
								for(var f in fields) {
									field = fields[f];
									if(typeof row[field] !== 'undefined') {
										row[field].display_value = message.data.record[field].display_value;
									}
								}
							}
						}
					}
				}

				$scope.$on('$destroy', function() {
					if (watcher)
						watcher.unsubscribe();
				});

				$scope.setPageNum = function(num) {
					$scope.data.p = num;
					getData(true);
					$timeout(function() {
						$scope.focusOnTableHeader();
					});
				};

				$scope.setOrderBy = function(field) {
					var d = "asc";
					if ($scope.data.o == field) {
						if ($scope.data.d == "asc")
							d = "desc";
						else
							d = "asc";
					}

					if (d === "asc") {
						spAriaUtil.sendLiveMessage($scope.data.msg.sortingByAsc);
					} else if (d === "desc") {
						spAriaUtil.sendLiveMessage($scope.data.msg.sortingByDesc);
					}

					$scope.data.o = field;
					$scope.data.d = d;
					$scope.setSearch(true);
				};

				$scope.setSearch = function(updateUrl) {
					$scope.data.p = 1;
					getData(updateUrl);
				};

				$scope.$on(eventNames.setFilter, function(e, newFilter){
					$scope.data.filter = newFilter;
					$scope.setSearch(false);
				});

				$scope.$on(eventNames.setKeywords, function(e, keywords){
					$scope.data.keywords = keywords;
					$scope.setSearch(false);
				});

				$scope.$on('widget-filter-breadcrumbs.queryModified', function(e, newFilter){
					$scope.data.filter = newFilter;
					$scope.setSearch(true);
				});

				$scope.rowsWerePruned = function() {
					if (!$scope.data.list)
						return;

					$scope.rowsPruned = $scope.mathMin($scope.data.window_end,$scope.data.row_count) - $scope.data.window_start - $scope.data.list.length;
					return $scope.rowsPruned > 0;
				};

				$scope.showFilter = function() {
					return !$scope.data.list.length && !$scope.data.num_pages && !$scope.data.invalid_table && !$scope.loadingData;
				};

				c.appendQuery = function(query){
					if ($scope.data.filter.length > 1)
						$scope.data.filter += '^';
					$scope.data.filter += query;
					$scope.setSearch();

				};

				// Makes Widget Async
				$scope.data = $scope.options;
				$scope.loadingData = true;
				$scope.server.update().then(function() {
					if ($scope.data.newButtonUnsupported)
						jslog("Service Portal: New button not supported for sys_attachment list");
					$scope.loadingData = false;
					initRecordWatcher($scope.data.table, $scope.data.filter);
					// STRY0101803 - moved to load in client so table updates
					loadFilterWidget();
				});

				function parseQuery(table, queryString){
					return $http.post('/api/now/sp/parsequery/' + table, queryString).then(function(response){
						return response.data.result;
					});
				}

				c.createQueryTerm = function(table, field, sys_id, operator){
					return $http.get('/api/now/sp/getInOutQueryTerm', {
						params: {
							table: table,
							sys_id: sys_id,
							field: field,
							operator: operator
						}
					}).then(function(response){
						if (response && response.data && response.data.result)
							return response.data.result.parts;
					});
				};

				c.showMatching = function(field, newTerm) {
					var queryString = $scope.data.filter;
					var eq = "";
					parseQuery($scope.data.table, queryString).then(function(oldTerms) {
						for(var i=0; i<oldTerms.length; i++){
							var term = oldTerms[i];
							if (isSameField(newTerm, term))
								continue;

							if (eq.length)
								eq += '^';

							eq += getEncodedTerm(term);
						}
						if (eq.length)
							eq += '^';
						eq += getEncodedTerm(newTerm);

						$scope.data.filter = eq;
						$scope.setSearch();
					});
				};

				c.filterOut = function(field, newTerm) {
					var eq = $scope.data.filter;
					if (eq.length)
						eq += '^';

					eq += getEncodedTerm(newTerm);
					$scope.data.filter = eq;
					$scope.setSearch();
				};

				function isSameField(t1, t2) {
					if ('left' in t1 && 'left' in t2)
						return t1.left.query_term_field === t2.left.query_term_field;
					else if ('left' in t1)
						return t1.left.query_term_field === t2.query_term_field;
					else if ('left' in t2)
						return t1.query_term_field === t2.left.query_term_field;
					return t1.query_term_field === t2.query_term_field;
				}

				function getEncodedTerm(term) {
					var eq;
					if (term.left) {
						eq = getEncodedTerm(term.left);
						eq += '^OR';
						eq += getEncodedTerm(term.right);
					} else {
						eq = term.query_term_field;
						eq += term.operator;
						eq += term.value;
					}
					return eq;
				}
			}

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.01.2020 | KT  | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------
.panel-default > .panel-heading .badge {
  background-color: $banner-count-bg;
  color: $banner-count-text;
  /* 2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing; Added height for badge */
  height: 20px;
}
//------------------------------------------------------------------------------------------------------------------------

.dtech-border-none {
  border:none;
}

.dtech-box {
  display: flex;
}

/* Must be a descendant of the class dtech-box */
.dtech-box .dtech-flex-space-15px {
  width: 15px;
}

/* Must be a descendant of the class dtech-box */
.dtech-box .dtech-push-right {
  margin-left: auto;
}

.dtech-dropdown-header {
  /* color: #3A3F51; */
  font-size: 14px;
  font-weight: 500;
  /* 2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing; Added padding */
  padding: 10px 20px;
}
/* Bootstrap 3.3.6 default: .dropdown-menu > li > a:hover, .dropdown-menu > li > a:focus { */
.dropdown-menu > li > ul > li > a:hover, .dropdown-menu > li > ul > li > a:focus {
  text-decoration: none;
  color: #2f3342;
  background-color: #f5f5f5;
}

.dtech-filter-menu {
  /*
  2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing; Added box-shadow
  Note using rgba, (Red Green Blue Alpha) that controls the opacity or transparency 
  that follows the same percentage scheme: 0% represents absolute transparency and 100% represents absolute opacity 
  */
  box-shadow: 0 6px 12px rgba(0, 0, 0, .25); /* yields: box-shadow: 0 6px 12px rgb(0 0 0 / 25%); */
  /* if not using left: auto */
  /* left: -400px; */
  left: auto; /* allows width to grow as needed */

  /* if not using .dtech-scrollable-menu */
  /* right: 29px; */
  right: 45px;
  /* 2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing; Changed top, was -250 */
  top: -300px;
}

.dtech-margin-right-5px {
  margin-right: 5px;
}

.dtech-inline-start {
  padding-left: 15px;
}

.dtech-pad-top-5px {
  padding: 5px 0;
}

.dtech-scrollable-menu {
  height: auto;
  /* 2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing; Changed max-height, was 500 */
  max-height: 700px;
  overflow-x: hidden;
}

.dtech-subMenu {
  list-style-type: none;
  padding: 2px 0;
}

.dtech-subMenu-item {
  color: #3A3F51;
  font-size: 14px;
  font-weight: normal;
}

.glyphicon {
  font-size: 12px;
  color: #3A3F51;
  padding: 3px;
}

