sp_widget.link:
function link(scope, element, attrs, ctrl){
	var $ul, $contextMenu;

	scope.focusOnTableHeader = function() {
		element.find(".data-table-title").attr("tabindex", "-1").focus();
	};

	element.on('contextmenu', function(e){
		if (e.ctrlKey)
			return; // ctrlKey is for the debug menu, not this menu

		var rowScope = angular.element(e.target).scope();
		var field, item, fieldVal;

		// Context Menu for tbody
		if (angular.isDefined(rowScope.field) && angular.isDefined(rowScope.item)){
			e.preventDefault();
			field = rowScope.field;
			item = rowScope.item;
			fieldVal = item[field].value;

			var items = [
			['${Show Matching}', function(){
				ctrl.createQueryTerm(scope.data.table, field, item.sys_id, '=').then(function(term){
					ctrl.showMatching(field, term);
				});
			}],
			['${Filter Out}', function(){
				ctrl.createQueryTerm(scope.data.table, field, item.sys_id, '!=').then(function(term){
					ctrl.filterOut(field, term);
				});
			}]
			];

			renderContextMenu(items);
			setContextMenuPosition(e);
		}
	});

	function renderContextMenu(items){
		var scrollHeight = $('body').get(0).scrollHeight;
		$contextMenu = angular.element('<div>', {'class': 'dropdown clearfix context-dropdown open'});

			$contextMenu.on('click', function (e) {
				if ($(e.target).hasClass('dropdown')) {
					_clearContextMenus(event);
				}
			});
			$contextMenu.on('contextmenu', function (event) {
				event.preventDefault();
				_clearContextMenus(event);
			});

			$contextMenu.css({
				position: 'absolute',
				top: 0,
				height: scrollHeight,
				left: 0,
				right: 0,
				zIndex: 9999
			});

			$('body').append($contextMenu);

			$ul = angular.element('<ul>', {
				'class': 'dropdown-menu',
				'role': 'menu'
			});
			renderItems();
			$contextMenu.append($ul);

			function renderItems(){
				angular.forEach(items, function (item) {
					var $li = angular.element('<li>');

					if (item === null) {
						$li.addClass('divider');
					} else {
						var $a = angular.element('<a>');
						$a.attr({tabindex: '-1', href:'#'});
							$a.text(item[0]);
							$li.append($a);
							$li.on('click', function (e) {
								e.preventDefault();
								scope.$apply(function () {
									_clearContextMenus(e);
									item[1].call(item, item);
								});
							});
						}

						$ul.append($li);
					});
				}
			}

			function _clearContextMenus(event){
				if (!event){
					return;
				}

				angular.element(event.currentTarget).removeClass('context');

				var els = angular.element(".context-dropdown");
				angular.forEach(els, function(el){
					angular.element(el).remove();
				});
			}

			var contextMenuItemHeight = 0;
			function setContextMenuPosition(event){
				if (contextMenuItemHeight === 0)
					contextMenuItemHeight = $ul.children(0).height();

				// Why not just call .width() and .height() on the container? Because those calculations cause browsers to reflow
				// that can cause IE10 to take 200ms to render a context menu.
				var cmWidth = 150;
				var cmHeight = contextMenuItemHeight * $ul.children().length;
				var startX = event.pageX + cmWidth >= window.innerWidth ? event.pageX - cmWidth : event.pageX;
				var startY = event.pageY + cmHeight >= window.innerHeight ? event.pageY - cmHeight : event.pageY;

				$ul.css({
					display: 'block',
					position: 'absolute',
					left: startX,
					top: startY,
					'min-width': cmWidth
				});
			}
		}

sp_widget.script:
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: TASKER DATA TABLE
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
//------------------------------------------------------------------------------------------------------------------------
//
// 2.6.0 | 2021-04-06 | mmcc | STRY0097980 - Hover Over Task Name HTML
// 2.6.0 | 2021-04-23 | mmcc | STRY0090503 Closed Incomplete is missing the color in the filter widget on the Modern 
//                                         Portal page and Chevron color is missing on the task form. 
//                                         Change made in CSS only.
// 2.6.0 | 2021-04-26 | mmcc | STRY0100152 - Tasker Modern Portal - Task Name Hover needs a short delay before showing the popup
//                                         Changes made in HTML, CSS, Server script and Client Controller
// 2.7.0 | 2021-05-20 | raj  | STRY0079526 - Undefined modal title when opening a "open task in modal" from the modern portal
//																					Changes made in HTML
//																					Changes made in Client Script
// 2.7.0 | 06.11.2021 | raj | STRY0101803: Updated to make more configable - added the ability to configure Order by, order direction, and fields
//                                   Updates in HTML, Client and Server
// 2.7.0 | 07.19.2021 | raj | Add 4 new OOTB Tasker Portal filters that show tasks in OUs you are a member of
//                                   Updates Server
// 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
//                                         HTML: major rewrite, got rid of pull-right per Bootstrap's documentation for dropdowns
//                                         CSS: add .dtech-* classes to style the dropdown for more options Filter
//                                         Server script: Get Filter Menu Headers, programmatically add the None header in case a User changes it,
//                                          Create an object to hold the Filter Menu Header string and an array of submenu items then push to the data.filters[]
//                                         Changes made in HTML, CSS, Server script
// 2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
//                                         In HTML, removed duplicate tooltip-popup-delay="200"
//                                         In CSS, selector .taskform-classification-banner declaration removed. Comment added to direct 
// 											to Tasker Theme then CSS include: Classification Banner CSS Include.
//                                          selector .restricted-group declaration removed. Comment added to direct 
// 											 to Tasker Theme then CSS include: Restricted Group Banner CSS Include. 
//                                         Changes made in HTML and CSS
// 2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing
//                                         In HTML, added CSS selector dtech-border-none
// 									       In CSS, updated CSS selectors: dtech-dropdown-header, panel-default >, dtech-filter-menu, dtech-scrollable-menu
//                                         Changes made in HTML and CSS
// 2.7.0 | 2021-08-23 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
//                                         Round 2. In HTML, removed comments from ng repeat for State
//                                         In CSS, Move State styling to Tasker State CSS Include. Move Status styling to Tasker Status CSS Include
//                                         Changes made in HTML and CSS

// 2.7.0 | 2021-08-23 | raj  | STRY0108629 - DIA- Org Hierarchy Request- Respond Hierarchy Update Bifold
//                                         Changes made in client script only
// 2.7.0 | 2021-08-23 | mmcc | DFCT0010441 - On the Modern Portal in the filter menu "-- None --" text displays
//                                         In Server script, remove code that added a Filter Menu Header named None
//                                         Changes made in Server script
//
// 2.7.0 | 2021-10-07 | raj  | DFCT0010547 - Clicking on the "Filter" query on the modern portal does NOT change the filter query
//																				 Filter breadcrumbs are now loaded in the client.  So, rather than broadcasting, just reset in client
//                                         Changes made in Client script
// 2.7.0 | 2021-10-07 | raj  | DFCT0010566 - Clicking on the "Filter" boxes on the modern portal does NOT change the filter query
//																				 Filter breadcrumbs are now loaded in the client.  So, rather than broadcasting, just reset in client
//                                         Changes made in Client script

//------------------------------------------------------------------------------------------------------------------------

(function() {

    // TODO - REMOVE THIS WHEN THE UPDATE IS MADE TO CHECK DATE ON THE SERVER
    g_taskUserFormPreferences = undefined;
    data.userID = gs.getUserID();
    // STRY0101803 - load user preferences object for use when opening forms
    // only load this one time
    if (!data.OUsWhereIamAMember)
        data.OUsWhereIamAMember = new x_153465_discovert.tasking_System_Settings_Scripts().getOUsWhereIamAMember();
    if (!data.OUsWhereIamATaskManager) {
        data.OUsWhereIamATaskManager = new x_153465_discovert.tasking_System_Settings_Scripts().getMyOUTaskManagers();
    }
    var oUserPref = new x_153465_discovert.tasker_User_Form_Preferences();
    data.userPreferences = oUserPref.loadMyFormPreferences(data.OUsWhereIamAMember, data.OUsWhereIamATaskManager);

    if (!input) // asynch load list
        return;

    // 2.7.0 | 2021-06-30 | raj | STRY0101803 Added Open in Platform to open the list with the fitler in platform
    data.hasRoleTaskerUser = gs.hasRole('x_153465_discovert.tasker_user');

    data.msg = {};
    data.msg.sortingByAsc = gs.getMessage("Sorting by ascending");
    data.msg.sortingByDesc = gs.getMessage("Sorting by descending");
    data.popOver = "active";
    /*
     * data.table = the table
     * data.p = the current page starting at 1
     * data.o = the order by column
     * data.d = the order by direction
     * data.keywords = the keyword search term
     * data.list = the table data as an array
     * data.invalid_table = true if table is invalid or if data was not succesfully fetched
     * data.table_label = the table's display name. e.g. Incident
     * data.table_plural = the table's plural display name. e.g. Incidents
     * data.field_list = a comma delimited list of field names to show in the data table
     * data.column_labels = a map of field name -> display name
     * data.window_size = the number of rows to show
     * data.filter = the encoded query
     */
    // copy to data[name] from input[name] || option[name]

    optCopy(['table', 'p', 'o', 'd', 'filter', 'filterACLs', 'field_list', 'keywords', 'view']);
    optCopy(['relationship_id', 'apply_to', 'apply_to_sys_id', 'window_size']);
    // STRY0101803
    optCopy(['modal_title_field_separator', 'modal_title_fields', 'include_comments','DiscoverControllerURL']);
    if (!data.table) {
        data.invalid_table = true;
        data.table_label = "";
        return;
    }
    // STRY0101803 - changed how data.fields is loaded to include udpates from the fitler selection
    if (!data.field_list) {
        if (data.view)
            data.field_list = $sp.getListColumns(data.table, data.view);
        else
            data.field_list = $sp.getListColumns(data.table);
    }
    data.fields = data.field_list;
    if (!data.modal_title_fields)
        data.modal_title_fields = '';

    data.filters = [];
    data.title = input.headerTitle;
    data.view = data.view || 'mobile';
    data.table = data.table || $sp.getValue('table');
    data.filter = data.filter || $sp.getValue('filter');

    // STRY0101803 -default to true if not set
    if (input.include_comments == undefined)
        data.include_comments = true;

    data.keywords = data.keywords || $sp.getValue('keywords');
    data.p = data.p || $sp.getValue('p') || 1;
    data.p = parseInt(data.p);
    data.o = data.o || $sp.getValue('o') || $sp.getValue('order_by');
    data.d = data.d || $sp.getValue('d') || $sp.getValue('order_direction');

    data.page_index = data.p - 1;
    data.show_new = data.show_new || options.show_new;
    var windowSize = data.window_size || $sp.getValue('maximum_entries') || 20;
    windowSize = parseInt(windowSize);
    if (isNaN(windowSize) || windowSize < 1)
        windowSize = 20;
    data.window_size = windowSize;
    if (input) {
        data.filter = input.filter;
    }

    // 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
    // Get an array filled with the Filter Menu Headers to use in the Filter More options
    var gr_filterMenuHeaders = new GlideRecord('sys_choice');
    gr_filterMenuHeaders.addQuery('name', 'x_153465_discovert_tasker_filters');
    gr_filterMenuHeaders.addQuery('element', 'u_filter_menu_header');
    gr_filterMenuHeaders.addQuery('inactive', 'false');
    gr_filterMenuHeaders.orderBy('sequence');
    gr_filterMenuHeaders.query();

    while (gr_filterMenuHeaders.next()) {
        var menuItem = {
            header: gr_filterMenuHeaders.getDisplayValue(),
            subMenus: []
        };

        data.filters.push(menuItem);
    }

    // get filter from filters table
    // STRY0101803 - had to change to glide record as some users couldn't see the Table field
    var gr_filters = new GlideRecord('x_153465_discovert_tasker_filters');
    gr_filters.addQuery('u_active', true);
    gr_filters.orderBy('u_order');
    gr_filters.orderBy('u_filter_label');
    gr_filters.query();

    while (gr_filters.next()) {
        // STRY0099083
        var currentFilter = gr_filters.getDisplayValue('u_filter');
        if (currentFilter.indexOf("OUsWhereIamAMember") > 0) {
            currentFilter = currentFilter.replace("OUsWhereIamAMember", data.OUsWhereIamAMember);
        }

				// STRY0108629
				var DiscoverControllerURL = gr_filters.getValue('u_discover_controller_url');
				DiscoverControllerURL = DiscoverControllerURL != null ? (DiscoverControllerURL == true) : false;

        // 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
        // Create the filter then push later
        var filter = {
            table: gr_filters.getDisplayValue('u_table.name'),
            // STRY0101803
            field_list: gr_filters.getDisplayValue('u_field_list') + '',
            modal_title_fields: gr_filters.getDisplayValue('u_modal_title_fields') + '',
            modal_title_field_separator: gr_filters.getDisplayValue('u_modal_title_field_separator') + '',
            // STRY0101803 load the "hover over field" from the filter defnition if set
            hoverField: gr_filters.getDisplayValue('u_hover_field') + '',
            filter_label: gr_filters.getDisplayValue('u_filter_label'),
            filter: currentFilter,
            view_all_page: gr_filters.getDisplayValue('u_view_all_page'),
            // STRY0101803
            // 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
            // include_comments: gr_filters.getDisplayValue('u_include_comments'),
            include_comments: gr_filters.getValue('u_include_comments'),
						// STRY0108629
						DiscoverControllerURL: DiscoverControllerURL,
            o: gr_filters.getDisplayValue('u_order_by'),
            d: gr_filters.getDisplayValue('u_direction')
        };

        // 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
        // Need the array element to push subMenus onto the Filter Menu Header
        var position = -1;
        if (gr_filters.getDisplayValue('u_filter_menu_header') != undefined) {
            position = getFilterMenuHeaderPosition(gr_filters.getDisplayValue('u_filter_menu_header'));
        }

        // 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
		// 2.7.0 | 2021-08-23 | mmcc | DFCT0010441 - On the Modern Portal in the filter menu "-- None --" text displays
        // update subMenus if the Filter Menu Header exists
		// if position = -1 then check the Filter Menu Header dropdown on Modern Portal Views or Choices table
		if (position > -1) {
			data.filters[position].subMenus.push(filter);
		}
    }
    // get task count for filter menu
    data.filtersFlag = false;
    // 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
    // Use forEach to get the counts
    data.filters.forEach(function(menuItem) {
        menuItem.subMenus.forEach(function(subMenu) {
            var count = new GlideAggregate(subMenu.table);
            count.addEncodedQuery(subMenu.filter);
            count.addAggregate('COUNT');
            count.query();
            if (count.next()) {
                subMenu.count = count.getAggregate('COUNT');
            }

            // 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
            // no data goes into the span and nothing is shown therefore removing
            if (subMenu.count > 0) {
                data.filtersFlag = true;
            }
        });
    });

    var gr;
    if (gs.getProperty("glide.security.ui.filter") == "true") {
        gr = new GlideRecord(data.table);
        gr.applyRowSecurity();
    } else
        gr = new GlideRecordSecure(data.table);
    if (!gr.isValid()) {
        data.invalid_table = true;
        data.table_label = data.table;
        return;
    }

    data.canCreate = gr.canCreate();
    data.newButtonUnsupported = data.table == "sys_attachment";
    data.table_label = gr.getLabel();
    //data.table_plural = gr.getPlural();
    if (data.filter) {
        if (data.filterACLs)
            gr = $sp.addQueryString(gr, data.filter);
        else
            gr.addEncodedQuery(data.filter);
    }

    if (data.keywords) {
        gr.addQuery('123TEXTQUERY321', data.keywords);
        data.keywords = null;
    }

    data.filter = gr.getEncodedQuery();

    if (data.relationship_id) {
        var rel = GlideRelationship.get(data.relationship_id);
        var target = new GlideRecord(data.table);
        var applyTo = new GlideRecord(data.apply_to);
        applyTo.get("sys_id", data.apply_to_sys_id);
        rel.queryWith(applyTo, target); // put the relationship query into target
        gr.addEncodedQuery(target.getEncodedQuery()); // get the query the relationship made for us
    }

    if (data.o) {
        if (data.d == "asc")
            gr.orderBy(data.o);
        else
            gr.orderByDesc(data.o);
    }

    data.window_start = data.page_index * data.window_size;
    data.window_end = (data.page_index + 1) * data.window_size;
    gr.chooseWindow(data.window_start, data.window_end);
    gr._query();

    data.row_count = gr.getRowCount();
    data.num_pages = Math.ceil(data.row_count / data.window_size);
    data.column_labels = {};
    // STRY0101803
    data.fields_array = data.field_list.split(",").map(function(item) {
        return item.trim();
    });
    data.modal_title_fields_array = [];
    if (data.modal_title_fields + '' != '') {
        data.modal_title_fields_array = data.modal_title_fields.split(",").map(function(item) {
            return item.trim();
        });
    }

    data.modal_title_fields_not_set = gs.getMessage('- Modal Title Fields Not Set');

    // use GlideRecord to get field labels vs. GlideRecordSecure
    var grForLabels = new GlideRecord(data.table);

    for (var i in data.fields_array) {
        var field = data.fields_array[i];
        var ge = grForLabels.getElement(field);

        //---------------------------------------------
        //STRY0071963: Servcienow Server JavaScript error getLabel in object null.
        /*if (ge == null)
				continue;

        data.column_labels[field] = ge.getLabel();
        */
        try {
            if (ge == null)
                continue;

            data.column_labels[field] = ge.getLabel();
        } catch (ex) {
            var message = ex.message;
            gs.error("Tasker error in Tasker Portal Board with Filter widget in field : " + message + " | field: " + field + " | ge: " + ge + " | i :" + i);
        }
        //---------------------------------------------		
    }
    data.popOverData = [];
    data.list = [];
    data.popOverRecord = {};
    while (gr.next()) {
        // calculate number of comments
        var numComments = 0;
        // STRY0101803 - allow comments to be hidden
        if (data.include_comments) {
            // STRY0101803, change to use data.table to support any table setup in the filter list or the options
            var stream = $sp.getStream(data.table, gr.getUniqueValue());
            for (var x = 0; x < stream.entries.length; x++) {
                if (stream.entries[x].element == 'comments') {
                    numComments++;
                }
            }
        }
        var record = {};
        // TODO, need to add table check here to support more tables		
        // state does page.		If we leave state, than no field will be badged
        //										If we change to allow a badge field, 
        //										then new field would either need to support the same states 
        //										or we would need a badge coding also
        // need to be able to define title fields and order and separator

        // need to define what loads in quick view for each table or at least set the title as it is different for task than the title on popup		
        var sys_id = gr.getUniqueValue();
        if (!data.popOverRecord[sys_id]) {
            switch (data.table) {
                case 'x_153465_discovert_route_task_instance':
                    // STRY0101803 set the default hover field for Task if not set, load if set
                    data.hoverField = (data.hoverField != undefined && data.hoverField != '') ? data.hoverField : 'short_description';
                    data.popOverRecord[sys_id] = {
                        'sys_id': gr.getUniqueValue(),
                        'title': gr.getDisplayValue('number') + ' - ' + gr.getDisplayValue('short_description'),
                        // 2.6.0 | 2021-04-06 | mmcc | STRY0097980 - Hover Over Task Name HTML; added u_top_task. as subtasks showed blank Objective
                        // "objective": gr.getDisplayValue('u_objective'),
                        "objective": gr.getDisplayValue('u_top_task.u_objective'),
                        "short_description": gr.getDisplayValue('short_description'),
                        "number": gr.getValue('number'),
                        "state": gr.getDisplayValue('state'),
                        "taskType": gr.getDisplayValue('tasker_type'),
                        "classification": gr.getDisplayValue('classification'),
                        "assignment_group": gr.getDisplayValue('assignment_group'),
                        'status': gr.getDisplayValue('status'),
                        'reviewer': gr.getDisplayValue('u_reviewer'),
                        'numComments': numComments
                    };
                    break;
                case 'x_153465_discovert_tasker_requests':
                    // STRY0101803 set the default hover field for request if not set, load if set
                    data.hoverField = (data.hoverField != undefined && data.hoverField != '') ? data.hoverField : 'u_request_comments';
                    data.popOverRecord[sys_id] = {
                        'sys_id': gr.getUniqueValue(),
                        'title': gr.getDisplayValue('number') + ' - ' + gr.getDisplayValue('parent.taskernumber') + ' - ' + gr.getDisplayValue('parent.short_description'),
                        // 2.6.0 | 2021-04-06 | mmcc | STRY0097980 - Hover Over Task Name HTML; added u_top_task. as subtasks showed blank Objective
                        // "objective": gr.getDisplayValue('u_objective'),
                        "objective": gr.getDisplayValue('parent.u_top_task.u_objective'),
                        "short_description": gr.getDisplayValue('parent.short_description'),
                        "number": gr.getValue('number'),
                        "state": gr.getDisplayValue('parent.state'),
                        // TODO, QUESTION, do we use request type here or task type or a combination of both?
                        // "taskType": gr.getDisplayValue('parent.tasker_type'),
                        "taskType": gr.getDisplayValue('parent.tasker_type') + ' - ' + gr.getDisplayValue('u_request_type'),
                        "classification": gr.getDisplayValue('parent.classification'),
                        "assignment_group": gr.getDisplayValue('parent.assignment_group'),
                        'status': gr.getDisplayValue('parent.status'),
                        'reviewer': gr.getDisplayValue('parent.u_reviewer'),
                        'numComments': numComments
                    };
                    break;
                case 'x_153465_discovert_tasker_schedule':
                    // STRY0101803 set the default hover field for request if not set, load if set
                    data.hoverField = (data.hoverField != undefined && data.hoverField != '') ? data.hoverField : 'u_request_comments';
                    data.popOverRecord[sys_id] = {
                        'sys_id': gr.getUniqueValue(),
                        'title': gr.getDisplayValue('number') + ' - ' + gr.getDisplayValue('name'),
                        // 2.6.0 | 2021-04-06 | mmcc | STRY0097980 - Hover Over Task Name HTML; added u_top_task. as subtasks showed blank Objective
                        // "objective": gr.getDisplayValue('u_objective'),
                        "objective": gr.getDisplayValue('tasker_process.u_objective'),
                        "short_description": gr.getDisplayValue('tasker_process.description'),
                        "number": gr.getValue('number'),
                        "state": gr.getDisplayValue('tasker_process.schedule_complete_flag'),
                        // TODO, QUESTION, do we use request type here or task type or a combination of both?
                        // "taskType": gr.getDisplayValue('parent.tasker_type'),
                        "taskType": gr.getDisplayValue('tasker_process.u_tasker_type'),
                        "classification": gr.getDisplayValue('tasker_process.classification'),
                        "assignment_group": gr.getDisplayValue('tasker_process.u_restricted_group'),
                        'status': gr.getLabel('tasker_process.next_run_date') + ' - ' + gr.getDisplayValue('tasker_process.next_run_date'),
                        'reviewer': gr.getDisplayValue('tasker_process.u_reviewer'),
                        'numComments': numComments
                    };
                    break;
            }

        }
        // STRY0101803, use the data.field_list instead of optoins.field_list so it is updated for each filter
        $sp.getRecordElements(record, gr, data.field_list);

        if (gr instanceof GlideRecordSecure) {
            // FilteredGlideRecord doesn't do field-level
            // security, so take care of that here
            for (var f in data.fields_array) {

                var fld = data.fields_array[f];
                if (!gr.isValidField(fld))
                    continue;

                if (!gr[fld].canRead()) {
                    record[fld].value = null;
                    record[fld].display_value = null;
                }
            }
        }
        switch (data.table) {
            case 'x_153465_discovert_route_task_instance':
                record.category = {};
                record.sub_category = {};
                record.tasker_type = {};
                record.state = {};
                record.category.display_value = gr.getDisplayValue('category');
                record.category.value = gr.getValue('category');
                record.sub_category.display_value = gr.getDisplayValue('sub_category');
                record.sub_category.value = gr.getValue('sub_category');
                record.tasker_type.display_value = gr.getDisplayValue('tasker_type');
                record.tasker_type.value = gr.getValue('tasker_type');
                record.state.display_value = gr.getDisplayValue('state');
                record.state.value = gr.getValue('state');
                break;
            case 'x_153465_discovert_tasker_requests':
                record.category = {};
                record.sub_category = {};
                record.tasker_type = {};
                record.state = {};
								// STRY0108629
								if(gr.parent){
									record.parentType = 'Task';
									record.category.display_value = gr.getDisplayValue('parent.category');
									record.category.value = gr.getValue('parent.category');
									record.sub_category.display_value = gr.getDisplayValue('parent.sub_category');
									record.sub_category.value = gr.getValue('parent.sub_category');
									record.tasker_type.display_value = gr.getDisplayValue('parent.tasker_type');
									record.tasker_type.value = gr.getValue('parent.tasker_type');
									record.state.display_value = gr.getDisplayValue('parent.state');
									record.state.value = gr.getValue('parent.state');
								} else {
									record.parentType = 'Organizational Unit';
									record.u_ou_parent = gr.getValue('u_ou_parent');
								}
                break;
            default:
                break;
        }
        record.sys_id = gr.getValue('sys_id');
				record.dcu_ref = '';
        // STRY0101803 set the id for the Task page based on the table of the filter
        switch (data.table) {
            case 'x_153465_discovert_route_task_instance':
                record.href_id = gr.getValue('sys_id');
                break;
            case 'x_153465_discovert_tasker_requests':
								if(gr.parent){
									record.href_id = gr.getValue('parent');
								} else{
									// STRY0108629
									record.href_id = gr.getValue('sys_id');
									record.dcu_ref = 'u_ou_parent';
								}
                break;
            case 'x_153465_discovert_tasker_schedule':
                record.href_id = gr.getValue('sys_id');
                break;
            default:
                record.href_id = gr.getValue('sys_id');
                break;
        }

        // 2.6.0 | 2021-04-26 | mmcc | STRY0100152 - Add a new boolean property to indicate when to show the tooltip
        record.isTooltipOpened = false;

        data.list.push(record);
    }

    data.enable_filter = (input.enable_filter == true || input.enable_filter == "true" ||
        options.enable_filter == true || options.enable_filter == "true");
    /*
    	var breadcrumbWidgetParams = {
    		table: data.table,
    		query: data.filter,
    		enable_filter: data.enable_filter
    	};

    	data.filterBreadcrumbs // = $sp.getWidget('widget-filter-breadcrumbs', breadcrumbWidgetParams);
    */

    function getFilterMenuHeaderPosition(menuHeader) {
        var position = -1;

        for (var i = 0; i < data.filters.length; i++) {
            if (data.filters[i].header == menuHeader) {
                position = i;
                break;
            }
        }

        return position;
    }

    // copy to data from input or options
    function optCopy(names) {
        names.forEach(function(name) {
            data[name] = input[name] || options[name];
        });
    }

})();
